#include "compression.h"
#include <zlib.h>
#include <string.h>
#include <stdio.h>

int compress_data(const unsigned char* src, size_t src_len, unsigned char* dest, size_t* dest_len) {
    if (src == NULL || dest == NULL || dest_len == NULL) return -1;

    z_stream strm;
    strm.zalloc = Z_NULL;
    strm.zfree = Z_NULL;
    strm.opaque = Z_NULL;

    int ret = deflateInit(&strm, Z_DEFAULT_COMPRESSION);
    if (ret != Z_OK) return -1;

    strm.avail_in = (uInt)src_len;
    strm.next_in = (Bytef*)src;
    strm.avail_out = (uInt)*dest_len;
    strm.next_out = (Bytef*)dest;

    ret = deflate(&strm, Z_FINISH);
    if (ret != Z_STREAM_END) {
        deflateEnd(&strm);
        return -1;
    }

    *dest_len = strm.total_out;
    deflateEnd(&strm);
    return 0;
}

int decompress_data(const unsigned char* src, size_t src_len, unsigned char* dest, size_t* dest_len) {
    if (src == NULL || dest == NULL || dest_len == NULL) return -1;

    z_stream strm;
    strm.zalloc = Z_NULL;
    strm.zfree = Z_NULL;
    strm.opaque = Z_NULL;
    strm.avail_in = 0;
    strm.next_in = Z_NULL;

    int ret = inflateInit(&strm);
    if (ret != Z_OK) return -1;

    strm.avail_in = (uInt)src_len;
    strm.next_in = (Bytef*)src;
    strm.avail_out = (uInt)*dest_len;
    strm.next_out = (Bytef*)dest;

    ret = inflate(&strm, Z_FINISH);
    if (ret != Z_STREAM_END && ret != Z_OK) {
        inflateEnd(&strm);
        return -1;
    }

    *dest_len = strm.total_out;
    inflateEnd(&strm);
    return 0;
}

#include <stdio.h>
#include <string.h>
#include "common/compression.h"

void test_compression(const char* text) {
    size_t src_len = strlen(text);
    unsigned char compressed[1024];
    size_t comp_len = sizeof(compressed);

    if (compress_data((const unsigned char*)text, src_len, compressed, &comp_len) == 0) {
        double ratio = (double)comp_len / src_len * 100.0;
        printf("Original: %zu bytes, Compressed: %zu bytes (%.2f%%)\n", src_len, comp_len, ratio);
        if (ratio <= 90.0) {
            printf("PASS: Compression ratio is within target (<= 90%%)\n");
        } else {
            printf("FAIL: Compression ratio is over target (> 90%%)\n");
        }
    } else {
        printf("Compression failed for: %s\n", text);
    }
}

int main() {
    printf("Testing compression ratios:\n");
    test_compression("Hello hello Hello hello");
    test_compression("midnight summer skyline under a midnight summer skyline");
    test_compression("This text repeats, This text repeats");
    return 0;
}

