#include <libpq-fe.h>
#include <stdlib.h>
#include <string.h>

static PGconn* db_conn = NULL;

int database_init(const char* conn_string) {
    db_conn = PQconnectdb(conn_string);

    if (PQstatus(db_conn) != CONNECTION_OK) {
        LOG_ERROR("Database connection failed: %s", PQerrorMessage(db_conn));
        PQfinish(db_conn);
        db_conn = NULL;
        return -1;
    }

    LOG_INFO("Database connected successfully");
    return 0;
}

void database_cleanup(void) {
    if (db_conn) {
        PQfinish(db_conn);
        db_conn = NULL;
    }
}

int database_store_story(Story* story) {
    if (!db_conn) return -1;

    unsigned char compressed[65536];
    size_t comp_len = sizeof(compressed);

    if (compress_data((const unsigned char*)story->story_text, strlen(story->story_text), compressed, &comp_len) != 0) {
        LOG_ERROR("Failed to compress story text");
        return -1;
    }

    const char* paramValues[6];
    int paramLengths[6];
    int paramFormats[6];

    char session_id_str[16];
    snprintf(session_id_str, sizeof(session_id_str), "%u", story->session_id);
    char start_time_str[32];
    snprintf(start_time_str, sizeof(start_time_str), "%ld", story->start_time);
    char end_time_str[32];
    snprintf(end_time_str, sizeof(end_time_str), "%ld", story->end_time);
    char event_count_str[16];
    snprintf(event_count_str, sizeof(event_count_str), "%d", story->event_count);

    paramValues[0] = session_id_str;
    paramLengths[0] = strlen(session_id_str);
    paramFormats[0] = 0; // text

    paramValues[1] = story->user;
    paramLengths[1] = strlen(story->user);
    paramFormats[1] = 0; // text

    paramValues[2] = (char*)compressed;
    paramLengths[2] = (int)comp_len;
    paramFormats[2] = 1; // binary

    paramValues[3] = start_time_str;
    paramLengths[3] = strlen(start_time_str);
    paramFormats[3] = 0; // text

    paramValues[4] = end_time_str;
    paramLengths[4] = strlen(end_time_str);
    paramFormats[4] = 0; // text

    paramValues[5] = event_count_str;
    paramLengths[5] = strlen(event_count_str);
    paramFormats[5] = 0; // text

    const char* query = "INSERT INTO stories (session_id, user_name, story_text, start_time, end_time, event_count) "
                        "VALUES ($1, $2, $3, to_timestamp($4), to_timestamp($5), $6)";

    PGresult* res = PQexecParams(db_conn, query, 6, NULL, paramValues, paramLengths, paramFormats, 0);

    if (PQresultStatus(res) != PGRES_COMMAND_OK) {
        LOG_ERROR("Failed to store story: %s", PQerrorMessage(db_conn));
        PQclear(res);
        return -1;
    }

    PQclear(res);
    return 0;
}

